 1	import React, { FC, useMemo } from 'react';
 2	import xbytes from 'xbytes';
 3	
 4	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 6	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 7	import ComponentReady from '@kubevirt-utils/components/Charts/ComponentReady/ComponentReady';
 8	import { getUtilizationQueries } from '@kubevirt-utils/components/Charts/utils/queries';
 9	import { getMemorySize } from '@kubevirt-utils/components/CPUMemoryModal/utils/CpuMemoryUtils';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { getMemory } from '@kubevirt-utils/resources/vm';
12	import { isEmpty } from '@kubevirt-utils/utils/utils';
13	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
14	import { ChartDonutUtilization } from '@patternfly/react-charts';
15	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
16	
17	type MemoryUtilProps = {
18	  vmi: V1VirtualMachineInstance;
19	};
20	
21	const MemoryUtil: FC<MemoryUtilProps> = ({ vmi }) => {
22	  const { t } = useKubevirtTranslation();
23	  const { currentTime, duration } = useDuration();
24	  const queries = useMemo(() => getUtilizationQueries({ duration, obj: vmi }), [vmi, duration]);
25	
26	  const memory = getMemorySize(getMemory(vmi));
27	
28	  const [data] = usePrometheusPoll({
29	    endpoint: PrometheusEndpoint?.QUERY,
30	    endTime: currentTime,
31	    namespace: vmi?.metadata?.namespace,
32	    query: queries?.MEMORY_USAGE,
33	  });
34	
35	  const memoryUsed = +data?.data?.result?.[0]?.value?.[1];
36	  const memoryAvailableBytes = xbytes.parseSize(`${memory?.size} ${memory?.unit}B`);
37	  const percentageMemoryUsed = (memoryUsed / memoryAvailableBytes) * 100;
38	  const isReady = !isEmpty(memory) && !Number.isNaN(percentageMemoryUsed);
39	
40	  return (
41	    <div className="util">
42	      <div className="util-upper">
43	        <div className="util-title">{t('Memory')}</div>
44	        <div className="util-summary" data-test-id="util-summary-memory">
45	          <div className="util-summary-value">
46	            {xbytes(memoryUsed || 0, { fixed: 0, iec: true })}
47	          </div>
48	          <div className="util-summary-text text-muted">
49	            <div>{t('Used of ')}</div>
50	            <div>{`${memory?.size} ${memory?.unit}B`}</div>
51	          </div>
52	        </div>
53	      </div>
54	      <div className="util-chart">
55	        <ComponentReady isReady={isReady}>
56	          <ChartDonutUtilization
57	            data={{
58	              x: t('Memory used'),
59	              y: Number(percentageMemoryUsed?.toFixed(2)),
60	            }}
61	            labels={({ datum }) =>
62	              datum.x ? `${datum.x}: ${xbytes(memoryUsed || 0, { iec: true })}` : null
63	            }
64	            animate
65	            constrainToVisibleArea
66	            style={{ labels: { fontSize: 20 } }}
67	            subTitle={t('Used')}
68	            subTitleComponent={<SubTitleChartLabel y={135} />}
69	            title={`${Number(percentageMemoryUsed?.toFixed(2))}%`}
70	            titleComponent={<TitleChartLabel />}
71	          />
72	        </ComponentReady>
73	      </div>
74	    </div>
75	  );
76	};
77	
78	export default MemoryUtil;

